Here is the complete, high-performance Kanban board designed explicitly around **Robert Murdock's Polaris Design System** and **Material Design 3 (M3)** specifications. 

It is pre-seeded with actual context from your project (Project Ollie / Project Friday) extracted from your sync documents (including items like Mike's coding agent, Cowboy's quality bash, and Mirjam's UXR track). It features automatic Light/Dark mode syncing and real-time multiplayer synchronization through the built-in flat-file synchronization framework.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Project Ollie - Kanban Tracker</title>

  <!-- Embedding Official Google Fonts -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">

  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;

      /* Material Design 3 Palette (Light Mode Default) */
      --md-primary: #0b57d0;
      --md-on-primary: #ffffff;
      --md-primary-container: #d3e3fd;
      --md-surface: #ffffff;
      --md-surface-container: #f0f4f9;
      --md-outline: #747775;
      --md-outline-variant: #c4c7c5;
      --md-text: #1f1f1f;
      --md-text-muted: #5f6368;
      --card-bg: #ffffff;
      --shadow-subtle: 0px 1px 3px rgba(0, 0, 0, 0.05);
    }

    @media (prefers-color-scheme: dark) {
      :root {
        /* Material Design 3 Palette (Dark Mode) */
        --md-primary: #a8c7fa;
        --md-on-primary: #062e6f;
        --md-primary-container: #0842a0;
        --md-surface: #131314;
        --md-surface-container: #1e1f20;
        --md-outline: #8e918f;
        --md-outline-variant: #444746;
        --md-text: #e3e3e3;
        --md-text-muted: #9e9e9e;
        --card-bg: #1e1f20;
        --shadow-subtle: 0px 1px 3px rgba(0, 0, 0, 0.3);
      }
    }

    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: 'Google Sans Text', sans-serif;
      background-color: var(--md-surface);
      color: var(--md-text);
      display: flex;
      flex-direction: column;
      height: 100vh;
      overflow: hidden;
      padding: var(--gemini-side-panel-padding-left) var(--gemini-side-panel-padding-right);
    }

    /* Minimal Header Styling */
    .app-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 12px 0 20px 0;
      border-bottom: 1px solid var(--md-outline-variant);
    }

    .app-title-group {
      display: flex;
      flex-direction: column;
    }

    .app-title {
      font-family: 'Google Sans', sans-serif;
      font-size: 18px;
      font-weight: 500;
      color: var(--md-text);
    }

    .app-subtitle {
      font-size: 12px;
      color: var(--md-text-muted);
      margin-top: 2px;
    }

    .sync-status {
      display: flex;
      align-items: center;
      gap: 6px;
      font-size: 12px;
      color: var(--md-text-muted);
      background-color: var(--md-surface-container);
      padding: 4px 10px;
      border-radius: 12px;
    }

    .sync-indicator {
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background-color: #34a853; /* Success green */
    }

    .sync-indicator.offline {
      background-color: #ea4335;
    }

    /* Board Layout - Extremely Minimal & Balanced */
    .board-container {
      display: flex;
      gap: 16px;
      flex: 1;
      overflow-x: auto;
      padding: 20px 0;
      align-items: flex-start;
    }

    .column {
      flex: 1;
      min-width: 280px;
      max-width: 400px;
      background-color: var(--md-surface-container);
      border-radius: 12px;
      display: flex;
      flex-direction: column;
      max-height: 100%;
      padding: 12px;
      border: 1px solid transparent;
      transition: background-color 0.2s, border-color 0.2s;
    }

    .column.drag-over {
      background-color: var(--md-primary-container);
      border: 1px dashed var(--md-primary);
    }

    .column-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 4px 8px 12px 8px;
    }

    .column-title {
      font-family: 'Google Sans', sans-serif;
      font-size: 14px;
      font-weight: 500;
      color: var(--md-text);
    }

    .card-count {
      font-size: 11px;
      background-color: var(--md-surface);
      color: var(--md-text-muted);
      padding: 2px 8px;
      border-radius: 10px;
      font-weight: 500;
      border: 1px solid var(--md-outline-variant);
    }

    /* Cards - Radical Cleanliness */
    .cards-list {
      display: flex;
      flex-direction: column;
      gap: 8px;
      flex: 1;
      overflow-y: auto;
      padding-bottom: 8px;
      min-height: 50px;
    }

    .card {
      background-color: var(--card-bg);
      border: 1px solid var(--md-outline-variant);
      border-radius: 8px;
      padding: 12px;
      position: relative;
      cursor: grab;
      user-select: none;
      box-shadow: var(--shadow-subtle);
      transition: box-shadow 0.15s, opacity 0.15s;
    }

    .card:active {
      cursor: grabbing;
    }

    .card.dragging {
      opacity: 0.4;
    }

    .card-text {
      font-size: 13px;
      line-height: 1.45;
      color: var(--md-text);
      word-wrap: break-word;
    }

    /* Hover Actions Overlay */
    .card-actions {
      display: flex;
      justify-content: flex-end;
      gap: 6px;
      margin-top: 8px;
      opacity: 0;
      transition: opacity 0.15s ease;
    }

    .card:hover .card-actions {
      opacity: 1;
    }

    .action-btn {
      background: none;
      border: none;
      cursor: pointer;
      font-size: 12px;
      color: var(--md-text-muted);
      padding: 2px 6px;
      border-radius: 4px;
      background-color: var(--md-surface-container);
      border: 1px solid var(--md-outline-variant);
      transition: background-color 0.15s, color 0.15s;
    }

    .action-btn:hover {
      background-color: var(--md-primary-container);
      color: var(--md-primary);
      border-color: var(--md-primary);
    }

    .action-btn.delete:hover {
      background-color: #fce8e6;
      color: #c5221f;
      border-color: #f5c2c1;
    }

    /* Quick Add Input Styling */
    .add-task-container {
      margin-top: 8px;
      border-top: 1px solid var(--md-outline-variant);
      padding-top: 8px;
    }

    .add-input {
      width: 100%;
      background-color: var(--card-bg);
      border: 1px solid var(--md-outline-variant);
      border-radius: 8px;
      padding: 8px 12px;
      font-size: 13px;
      font-family: inherit;
      color: var(--md-text);
      outline: none;
      transition: border-color 0.2s, box-shadow 0.2s;
    }

    .add-input:focus {
      border-color: var(--md-primary);
      box-shadow: 0 0 0 2px var(--md-primary-container);
    }
  </style>
</head>
<body>

  <!-- Dynamic Polaris Workspace Header -->
  <header class="app-header">
    <div class="app-title-group">
      <h1 class="app-title" id="workspace-title">Project Ollie Workspace</h1>
      <span class="app-subtitle" id="workspace-subtitle">Live Collaborative Tracking</span>
    </div>
    <div class="sync-status" id="sync-container">
      <span class="sync-indicator" id="sync-dot"></span>
      <span id="sync-text">Syncing...</span>
    </div>
  </header>

  <!-- Kanban Board Grid -->
  <main class="board-container">

    <!-- To Do Column -->
    <section class="column" id="col-todo" ondragover="allowDrop(event)" ondragenter="dragEnter(event)" ondragleave="dragLeave(event)" ondrop="drop(event, 'todo')">
      <div class="column-header">
        <h2 class="column-title">To Do</h2>
        <span class="card-count" id="count-todo">0</span>
      </div>
      <div class="cards-list" id="list-todo"></div>
      <div class="add-task-container">
        <input type="text" class="add-input" placeholder="＋ Add a task (Press Enter)" onkeydown="checkSubmit(event, 'todo')">
      </div>
    </section>

    <!-- In Progress Column -->
    <section class="column" id="col-inProgress" ondragover="allowDrop(event)" ondragenter="dragEnter(event)" ondragleave="dragLeave(event)" ondrop="drop(event, 'inProgress')">
      <div class="column-header">
        <h2 class="column-title">In Progress</h2>
        <span class="card-count" id="count-inProgress">0</span>
      </div>
      <div class="cards-list" id="list-inProgress"></div>
      <div class="add-task-container">
        <input type="text" class="add-input" placeholder="＋ Add a task (Press Enter)" onkeydown="checkSubmit(event, 'inProgress')">
      </div>
    </section>

    <!-- Done Column -->
    <section class="column" id="col-done" ondragover="allowDrop(event)" ondragenter="dragEnter(event)" ondragleave="dragLeave(event)" ondrop="drop(event, 'done')">
      <div class="column-header">
        <h2 class="column-title">Done</h2>
        <span class="card-count" id="count-done">0</span>
      </div>
      <div class="cards-list" id="list-done"></div>
      <div class="add-task-container">
        <input type="text" class="add-input" placeholder="＋ Add a task (Press Enter)" onkeydown="checkSubmit(event, 'done')">
      </div>
    </section>

  </main>

  <script>
    // Real Workspace & Synchronization Metadata
    const envId = window.__sandboxEnvId;
    const workspaceName = window.__sandboxWorkspaceName || "Project Ollie";
    const syncKey = "ollie_board_state_data";

    // Set Workspace Title Dynamic Display
    document.getElementById("workspace-title").textContent = `${workspaceName} Tracker`;
    document.getElementById("workspace-subtitle").textContent = envId ? "Synchronized in real-time with team" : "Local Storage Mode";

    // Seed State with actual tasks from Project Ollie workspace sync documents
    const defaultSeededState = {
      todo: [
        { id: "task-1", text: "UXR: Run next week's co-design sessions with Workspace Customers (NYC Office, July 15)" },
        { id: "task-2", text: "Security Audit: Verify data privacy controls for Directors+ access" },
        { id: "task-3", text: "Prototype Testing: Set up GCP environment for teamfood testing" }
      ],
      inProgress: [
        { id: "task-4", text: "Coding Agent: Implement scheduled job optimizations (Mike Carcasole)" },
        { id: "task-5", text: "Agent Quality: Fix chat streaming bugs and run bug bash (Cowboy Lynk & Ian)" },
        { id: "task-6", text: "UX/UI Refinements: Address bugs & improve Ollie main flow (Simon Sok)" }
      ],
      done: [
        { id: "task-7", text: "UXR Recruitment: Launch DScout project and capture 100 survey responses" },
        { id: "task-8", text: "Project Friday: Deliver MVP architectural overview presentation" }
      ]
    };

    let boardState = JSON.parse(JSON.stringify(defaultSeededState));
    let draggedCardId = null;
    let draggedSourceCol = null;

    // Load initial state
    async function loadState() {
      if (!envId) {
        // Local Fallback
        const saved = localStorage.getItem(syncKey);
        if (saved) {
          boardState = JSON.parse(saved);
        }
        updateSyncStatus(true);
        renderBoard();
        return;
      }

      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data) {
          // Deep comparison to prevent refreshing UI if nothing has actually changed
          if (JSON.stringify(json.data) !== JSON.stringify(boardState)) {
            boardState = json.data;
            renderBoard();
          }
        } else {
          // First time opening this space: push seeded state immediately
          await saveState(true);
        }
        updateSyncStatus(true);
      } catch (err) {
        console.error("Failed to load state:", err);
        updateSyncStatus(false);
      }
    }

    // Save active state to Synced Storage
    async function saveState(isInitialLoad = false) {
      if (!envId) {
        localStorage.setItem(syncKey, JSON.stringify(boardState));
        renderBoard();
        return;
      }

      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: boardState })
        });
        updateSyncStatus(true);
        if (!isInitialLoad) {
          renderBoard();
        }
      } catch (err) {
        console.error("Failed to save state:", err);
        updateSyncStatus(false);
      }
    }

    function updateSyncStatus(online) {
      const dot = document.getElementById("sync-dot");
      const text = document.getElementById("sync-text");
      if (online) {
        dot.classList.remove("offline");
        text.textContent = envId ? "Synced" : "Local Sync Enabled";
      } else {
        dot.classList.add("offline");
        text.textContent = "Offline Connection";
      }
    }

    // Render Board DOM
    function renderBoard() {
      const columns = ["todo", "inProgress", "done"];

      columns.forEach(col => {
        const listEl = document.getElementById(`list-${col}`);
        const countEl = document.getElementById(`count-${col}`);

        // Update Card Count Badge
        countEl.textContent = boardState[col].length;

        // Refresh items inside the list safely
        listEl.innerHTML = "";

        boardState[col].forEach(card => {
          const cardEl = document.createElement("div");
          cardEl.className = "card";
          cardEl.draggable = true;
          cardEl.dataset.id = card.id;

          cardEl.ondragstart = (e) => dragStart(e, card.id, col);
          cardEl.ondragend = dragEnd;

          // Plain text layout adhering strictly to radical simplicity
          cardEl.innerHTML = `
            <div class="card-text">${escapeHtml(card.text)}</div>
            <div class="card-actions">
              ${col !== 'todo' ? `<button class="action-btn" onclick="moveDirect('${card.id}', '${col}', 'left')">◀ Move</button>` : ''}
              ${col !== 'done' ? `<button class="action-btn" onclick="moveDirect('${card.id}', '${col}', 'right')">Move ▶</button>` : ''}
              <button class="action-btn delete" onclick="deleteCard('${card.id}', '${col}')">Delete</button>
            </div>
          `;

          listEl.appendChild(cardEl);
        });
      });
    }

    // Task Manipulations
    function checkSubmit(e, col) {
      if (e.key === "Enter" && e.target.value.trim() !== "") {
        const text = e.target.value.trim();
        const newCard = {
          id: "task-" + Date.now(),
          text: text
        };
        boardState[col].push(newCard);
        e.target.value = "";
        saveState();
      }
    }

    function deleteCard(cardId, col) {
      boardState[col] = boardState[col].filter(card => card.id !== cardId);
      saveState();
    }

    function moveDirect(cardId, currentCol, direction) {
      const targetCol = direction === 'left' 
        ? (currentCol === 'done' ? 'inProgress' : 'todo') 
        : (currentCol === 'todo' ? 'inProgress' : 'done');

      moveCard(cardId, currentCol, targetCol);
    }

    function moveCard(cardId, fromCol, toCol) {
      const cardIndex = boardState[fromCol].findIndex(c => c.id === cardId);
      if (cardIndex > -1) {
        const [card] = boardState[fromCol].splice(cardIndex, 1);
        boardState[toCol].push(card);
        saveState();
      }
    }

    // HTML5 native Drag & Drop implementation
    function dragStart(e, cardId, colId) {
      draggedCardId = cardId;
      draggedSourceCol = colId;
      e.target.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
    }

    function dragEnd(e) {
      e.target.classList.remove('dragging');
      document.querySelectorAll('.column').forEach(el => {
        el.classList.remove('drag-over');
      });
    }

    function allowDrop(e) {
      e.preventDefault();
    }

    function dragEnter(e) {
      e.currentTarget.classList.add('drag-over');
    }

    function dragLeave(e) {
      e.currentTarget.classList.remove('drag-over');
    }

    function drop(e, targetCol) {
      e.preventDefault();
      e.currentTarget.classList.remove('drag-over');
      if (draggedCardId && draggedSourceCol !== targetCol) {
        moveCard(draggedCardId, draggedSourceCol, targetCol);
      }
    }

    function escapeHtml(str) {
      return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
    }

    // Start Real-Time Short-polling Synchronization
    loadState();
    if (envId) {
      setInterval(loadState, 2000);
    }
  </script>
</body>
</html>
```
